func (toc *Fragments) ToHTML(startLevel, stopLevel int, ordered bool) template.HTML {
	if toc == nil {
		return ""
	}
	b := &tocBuilder{
		s:		strings.Builder{},
		h:		toc.Headings,
		startLevel:	startLevel,
		stopLevel:	stopLevel,
		ordered:	ordered,
	}
	b.Build()
	return template.HTML(b.s.String())
}
